import React, { useState } from 'react';

function ForecastCard(props) {

const {weather, city} = props;

  return (
    <div className='Weather-card Weather-card-flex'>
      <h1 className="City-name">{city.name}</h1>
      {/* <h2>{weather.dt_txt}</h2> */}
      <p>Projected Temperature: <span className='Color-bold'>{weather.main.temp}°</span> (L:{weather.main.temp_min}/H:{weather.main.temp_max})</p>
      <p>
      Wind Speed: {weather.wind.speed} mph
      </p>
      <p>
      Sunrise:{new Date(city.sunrise*1000).toLocaleTimeString()}
      </p>
      <p>
      Sunset:{new Date(city.sunset*1000).toLocaleTimeString()}
      </p>
        <h3>It will be a {weather.weather[0].description} kind of day 👩‍🚀</h3>
        <h2><img src={`https://openweathermap.org/img/w/${weather.weather[0].icon}.png`}/></h2>
    </div>
  );
}

export default ForecastCard;


